from pathlib import Path
FILES = {'skills/signal-core/profiles/roblox_studio/validators.py': 'from __future__ import annotations\n\nimport hashlib\nimport json\nfrom dataclasses import dataclass\nfrom typing import Any, Callable, Mapping\n\nfrom .errors import ValidationError\n\n\n@dataclass(frozen=True, slots=True)\nclass ValidationResult:\n    validator: str\n    passed: bool\n    detail: str\n\n\n@dataclass(frozen=True, slots=True)\nclass ProofNode:\n    requirement: str\n    evidence: tuple[str, ...]\n    execution: str\n    artifact_hash: str\n    validator_results: tuple[ValidationResult, ...]\n    observed_result: str\n    residual_risk: str\n\n\ndef validate_response_schema(response: Mapping[str, Any], required: set[str]) -> ValidationResult:\n    missing = required - set(response)\n    return ValidationResult("response_schema", not missing, "missing=" + ",".join(sorted(missing)))\n\n\ndef validate_artifact_hash(content: bytes, expected: str) -> ValidationResult:\n    actual = hashlib.sha256(content).hexdigest()\n    return ValidationResult("artifact_hash", actual == expected, actual)\n\n\ndef validate_capability(executed: set[str], authorized: set[str]) -> ValidationResult:\n    extra = executed - authorized\n    return ValidationResult("capability", not extra, "extra=" + ",".join(sorted(extra)))\n\n\ndef validate_budget(used: int, limit: int) -> ValidationResult:\n    return ValidationResult("budget", used <= limit, f"{used}/{limit}")\n\n\ndef require_all(results: tuple[ValidationResult, ...]) -> None:\n    failed = [result for result in results if not result.passed]\n    if failed:\n        raise ValidationError("; ".join(f"{item.validator}:{item.detail}" for item in failed))\n', 'skills/signal-core/profiles/roblox_studio/workflow.py': 'from __future__ import annotations\n\nimport json\nimport time\nfrom dataclasses import asdict, dataclass\nfrom enum import StrEnum\nfrom pathlib import Path\nfrom typing import Iterable, Mapping\n\nfrom .adapters.base import EngineAdapter, EngineRequest, EngineResponse\nfrom .budgets import BudgetLedger\nfrom .errors import WorkflowError\nfrom .validators import ValidationResult, require_all, validate_capability, validate_response_schema\n\n\nclass NodeState(StrEnum):\n    PENDING="PENDING"; READY="READY"; RUNNING="RUNNING"; BLOCKED="BLOCKED"; VALIDATING="VALIDATING"; SUCCEEDED="SUCCEEDED"; FAILED="FAILED"; ROLLED_BACK="ROLLED_BACK"; CANCELLED="CANCELLED"\n\n\n@dataclass(frozen=True, slots=True)\nclass WorkflowNode:\n    node_id: str\n    capability: str\n    dependencies: tuple[str, ...]\n    required_evidence: tuple[str, ...]\n    engine_id: str\n    timeout: int\n    retry_attempts: int\n    validator_names: tuple[str, ...]\n    rollback_action: str | None\n\n\n@dataclass(frozen=True, slots=True)\nclass NodeResult:\n    node_id: str\n    state: NodeState\n    response: EngineResponse | None\n    validations: tuple[ValidationResult, ...]\n    attempts: int\n\n\nclass CheckpointStore:\n    def __init__(self, path: Path) -> None:\n        self.path = Path(path)\n        self.path.parent.mkdir(parents=True, exist_ok=True)\n\n    def save(self, task_id: str, results: Iterable[NodeResult]) -> None:\n        payload = {"task_id": task_id, "results": [asdict(result) for result in results], "saved_at": time.time_ns()}\n        temp = self.path.with_suffix(".tmp")\n        temp.write_text(json.dumps(payload, default=str, sort_keys=True), encoding="utf-8")\n        temp.replace(self.path)\n\n    def exists(self) -> bool:\n        return self.path.exists()\n\n\nclass WorkflowExecutor:\n    def __init__(self, adapters: Mapping[str, EngineAdapter], checkpoint: CheckpointStore) -> None:\n        self.adapters = dict(adapters)\n        self.checkpoint = checkpoint\n\n    def execute(self, *, task_id: str, nodes: Iterable[WorkflowNode], authorized: set[str], budget: BudgetLedger, payload: Mapping[str, object]) -> tuple[NodeResult, ...]:\n        node_list = tuple(nodes)\n        completed: set[str] = set()\n        results: list[NodeResult] = []\n        for node in node_list:\n            if not set(node.dependencies).issubset(completed):\n                raise WorkflowError(f"node {node.node_id} dependencies are incomplete")\n            adapter = self.adapters.get(node.engine_id)\n            if adapter is None:\n                raise WorkflowError(f"engine adapter missing: {node.engine_id}")\n            budget.reserve(requests=1, wall_time_s=min(node.timeout, 1))\n            attempts = 0\n            response = None\n            while attempts < node.retry_attempts:\n                attempts += 1\n                response = adapter.execute(EngineRequest(node.capability, task_id, payload))\n                if response.status == "SUCCEEDED":\n                    break\n            if response is None or response.status != "SUCCEEDED":\n                result = NodeResult(node.node_id, NodeState.FAILED, response, (), attempts)\n                results.append(result)\n                self.checkpoint.save(task_id, results)\n                raise WorkflowError(f"node failed: {node.node_id}")\n            validations = (\n                validate_response_schema(response.payload, {"task_id", "capability", "artifact_hash"}),\n                validate_capability({node.capability}, authorized),\n            )\n            require_all(validations)\n            result = NodeResult(node.node_id, NodeState.SUCCEEDED, response, validations, attempts)\n            results.append(result)\n            completed.add(node.node_id)\n            self.checkpoint.save(task_id, results)\n        return tuple(results)\n', 'tests/roblox_profile/_support.py': 'from __future__ import annotations\n\nimport sys\nfrom pathlib import Path\n\nPROFILE_PARENT = Path(__file__).resolve().parents[2] / "skills" / "signal-core" / "profiles"\nif str(PROFILE_PARENT) not in sys.path:\n    sys.path.insert(0, str(PROFILE_PARENT))\n\nfrom roblox_studio.context_knapsack import ContextCandidate\nfrom roblox_studio.task_state import RobloxTaskState\n\n\ndef task_mapping(**overrides):\n    value = {\n        "schema_version": 2,\n        "task_id": "task-12345678",\n        "session_id": "session-12345678",\n        "place_id": "1001",\n        "project_id": "project-1001",\n        "project_fingerprint": "sha256:" + "a" * 64,\n        "studio_process_id": 4242,\n        "intent": "Inspect the project and read the target script",\n        "requested_capabilities": ["inspect_project", "read_script"],\n        "authorized_capabilities": ["inspect_project", "read_script"],\n        "evidence_requirements": ["definition", "implementation"],\n        "risk_class": "R1",\n        "privacy_class": "PROJECT",\n        "execution_constraints": ["simulated_only"],\n        "token_budget": 500,\n        "request_budget": 20,\n        "transfer_budget": 100000,\n        "gpu_budget": 0,\n        "wall_time_budget": 60,\n        "required_validators": ["response_schema", "capability"],\n        "rollback_requirements": [],\n        "completion_conditions": ["validators_pass"],\n    }\n    value.update(overrides)\n    return value\n\n\ndef task(**overrides):\n    return RobloxTaskState.from_mapping(task_mapping(**overrides))\n\n\ndef candidates():\n    return (\n        ContextCandidate("def", "definition", 50, 1.0, 1.0, 0.0, True, "Workspace contains ServerScriptService.Main", "memory://def"),\n        ContextCandidate("impl", "implementation", 70, 1.0, 1.0, 0.0, True, "print(\'hello\')", "memory://impl"),\n        ContextCandidate("noise", "implementation", 250, 0.1, 0.2, 0.9, False, "outdated unrelated documentation", "memory://noise"),\n    )\n', 'tests/roblox_profile/test_activation.py': 'from __future__ import annotations\n\nimport copy\nimport threading\nimport unittest\nfrom pathlib import Path\nfrom tempfile import TemporaryDirectory\n\nfrom _support import PROFILE_PARENT\nfrom roblox_studio.activation import ReplayStore, mint_envelope, verify_envelope\nfrom roblox_studio.errors import ActivationError, ReplayDetected\n\n\nclass ActivationTests(unittest.TestCase):\n    key = b"k" * 48\n    now = 2_000_000_000\n\n    def envelope(self, **overrides):\n        kwargs = dict(\n            key=self.key, session_id="studio-session-123", place_id="1001", project_id="project-1001",\n            project_fingerprint="sha256:" + "a" * 64, studio_process_id=4242,\n            capabilities=("inspect_project", "read_script"), transport_identity="bridge-abc-123",\n            now=self.now, ttl_seconds=60, nonce="nonce-1234567890",\n        )\n        kwargs.update(overrides)\n        return mint_envelope(**kwargs)\n\n    def verify(self, envelope, store, **overrides):\n        kwargs = dict(\n            key=self.key, replay_store=store, allowed_capabilities=("inspect_project", "read_script"),\n            expected_transport_identity="bridge-abc-123", expected_process_id=4242,\n            expected_place_id="1001", expected_project_id="project-1001",\n            expected_project_fingerprint="sha256:" + "a" * 64,\n            process_attestor=lambda pid: pid == 4242, now=self.now,\n        )\n        kwargs.update(overrides)\n        return verify_envelope(envelope, **kwargs)\n\n    def test_valid_envelope(self):\n        with TemporaryDirectory() as temp:\n            session = self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"))\n            self.assertEqual(session.project_id, "project-1001")\n\n    def test_unsigned_rejected(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(); envelope.pop("signature")\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_invalid_signature(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(); envelope["signature"] = "bad"\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_expired(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(now=self.now-500), ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_future_issued(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(now=self.now+60), ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_replay(self):\n        with TemporaryDirectory() as temp:\n            store = ReplayStore(Path(temp) / "nonce.db"); envelope = self.envelope()\n            self.verify(envelope, store)\n            with self.assertRaises(ReplayDetected): self.verify(envelope, store)\n\n    def test_wrong_process(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), expected_process_id=999)\n\n    def test_attestor_failure(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), process_attestor=lambda pid: False)\n\n    def test_wrong_project(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), expected_project_id="other")\n\n    def test_wrong_place(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), expected_place_id="other")\n\n    def test_fingerprint_mismatch(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), expected_project_fingerprint="sha256:"+"b"*64)\n\n    def test_transport_mismatch(self):\n        with TemporaryDirectory() as temp:\n            with self.assertRaises(ActivationError): self.verify(self.envelope(), ReplayStore(Path(temp) / "nonce.db"), expected_transport_identity="other")\n\n    def test_capability_escalation(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(capabilities=("write_script",))\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_malformed_capability_set(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(); payload = {k:v for k,v in envelope.items() if k != "signature"}; payload["capabilities"] = "inspect_project"\n            from roblox_studio.activation import sign_payload\n            envelope = {**payload, "signature": sign_payload(payload, self.key)}\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_cross_profile_confusion(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(); payload = {k:v for k,v in envelope.items() if k != "signature"}; payload["profile_id"] = "generic"\n            from roblox_studio.activation import sign_payload\n            envelope = {**payload, "signature": sign_payload(payload, self.key)}\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_oversized_payload(self):\n        with TemporaryDirectory() as temp:\n            envelope = self.envelope(); envelope["extra"] = "x" * 20000\n            with self.assertRaises(ActivationError): self.verify(envelope, ReplayStore(Path(temp) / "nonce.db"))\n\n    def test_nonce_race_accepts_exactly_one(self):\n        with TemporaryDirectory() as temp:\n            store = ReplayStore(Path(temp) / "nonce.db"); envelope = self.envelope()\n            outcomes=[]\n            def worker():\n                try: self.verify(envelope, store); outcomes.append("accepted")\n                except ReplayDetected: outcomes.append("replay")\n            threads=[threading.Thread(target=worker) for _ in range(8)]\n            [thread.start() for thread in threads]; [thread.join() for thread in threads]\n            self.assertEqual(outcomes.count("accepted"), 1)\n            self.assertEqual(outcomes.count("replay"), 7)\n\n\nif __name__ == "__main__": unittest.main()\n'}
